#include<bits/stdc++.h>
using namespace std;
int main(){
    int n,m,ans=1,a[510][510],f[510][510];
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++,ans++){
            a[i][j]=ans;
        }
    }
    while(m--){
        int x,y,r,z;
        cin>>x>>y>>r>>z;
        int nn=r*2+1;
        int x1=x-r,x2=x+r,y1=y-r,y2=y+r;
        for(int i=x1;i<=x2;i++){
            for(int j=y1;j<=y2;j++){
                if(z==0) f[(j-y1)+x1][nn-(i-x1+1)+y1]=a[i][j];
                else f[nn-(j-y1+1)+x1][i-x1+y1]=a[i][j];
            }
        }
        for(int i=x1;i<=x2;i++){
            for(int j=y1;j<=y2;j++){
                a[i][j]=f[i][j];
            }
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            cout<<a[i][j]<<" ";
        }cout<<"\n";
    }
    return 0;
}
